    this.description = "Modular, self-adaptive translational signal for philosophical/ethical framework propagation";

    // Core detection patterns for various formats
    this.formatDetectors = {
      json: (content) => {
        try {
          JSON.parse(content);
          return true;
        } catch {
          return false;
        }
      },

      xml: (content) => {
        return /<[^>]+>/.test(content) && content.includes('</');
      },

      yaml: (content) => {
        return /^[\s]*[\w-]+\s*:\s*/.test(content) && !content.includes('{');
      },

      html: (content) => {
        return /<html|<head|<body|<!DOCTYPE/i.test(content);
      },

      css: (content) => {
        return /[\w-]+\s*{[^}]*}/.test(content) || /@\w+/.test(content);
      },

      javascript: (content) => {
        return /\b(function|const|let|var|class|import|export)\b/.test(content);
      },

      python: (content) => {
        return /\b(def|class|import|from|if __name__)\b/.test(content);
      },

      markdown: (content) => {
        return /^#+\s|\*\*|__|```/.test(content);
      },

      ini: (content) => {
        return /^\[[^\]]+\]$/m.test(content) && /^\w+\s*=/.test(content);
      },

      sql: (content) => {
        return /\b(SELECT|INSERT|UPDATE|DELETE|CREATE|ALTER)\b/i.test(content);
      },

      plaintext: () => true // Default fallback
    };

    // Translators for each format
    this.translators = {
      json: this.translateToJSON.bind(this),
      xml: this.translateToXML.bind(this),
      yaml: this.translateToYAML.bind(this),
      html: this.translateToHTML.bind(this),
      css: this.translateToCSS.bind(this),
      javascript: this.translateToJavaScript.bind(this),
      python: this.translateToPython.bind(this),
      markdown: this.translateToMarkdown.bind(this),
      ini: this.translateToINI.bind(this),
      sql: this.translateToSQL.bind(this),
      plaintext: this.translateToPlaintext.bind(this)
    };

    // Transmission modes
    this.transmissionModes = {
      EMBED: 'embed',      // Integrate into existing structure
      PREPEND: 'prepend',  // Add at beginning
      APPEND: 'append',    // Add at end
      REPLACE: 'replace',  // Replace specific sections
      COMMENT: 'comment',  // Insert as comments
      METADATA: 'metadata' // Add as metadata/headers
