Here’s a simple Node.js script using ethers.js that will scan an Ethereum address for any ERC‑20 token “dust” balances and send them back to your main wallet. You’ll need:  
• Your private key for a funding account (with enough ETH to pay gas)  
• The RPC URL for the network you’re targeting (mainnet, Goerli, etc.)  

––––––––––––––––––––––––––––––––––––––––––  
```js
// dust‑sweeper.js
//
// Scans a wallet for ERC‑20 dust and transfers any nonzero balances
// back to your main “collector” address.

// Install dependencies first:
//   npm install ethers dotenv

require('dotenv').config();
const { ethers } = require('ethers');

// ———————————————— CONFIGURATION ————————————————  
// Put these in a file named “.env” next to this script:
// 
// RPC_URL=YOUR_ETHEREUM_RPC_URL
// PRIVATE_KEY=YOUR_WALLET_PRIVATE_KEY
// COLLECTOR_ADDRESS=0xYourMainWalletAddress

const RPC_URL = process.env.RPC_URL;
const wallet = new ethers.Wallet(process.env.PRIVATE_KEY);
const provider = new ethers.providers.JsonRpcProvider(RPC_URL);
const signer = wallet.connect(provider);
const collector = process.env.COLLECTOR_ADDRESS;

// A minimal ERC‑20 ABI to read balance and send transfer.
const ERC20_ABI = [
  'function balanceOf(address) view returns (uint256)',
  'function transfer(address to, uint amount) returns (bool)'
];

// List here the token contract addresses you want to sweep dust from.
// For a more dynamic approach you could fetch from a block‑explorer API.
const TOKENS = [
  '0xTokenAddress1',
  '0xTokenAddress2',
  // …
];

async function sweepDust() {
  console.log('Starting dust sweep…');
  for (const tokenAddr of TOKENS) {
    const token = new ethers.Contract(tokenAddr, ERC20_ABI, signer);
    const balance = await token.balanceOf(wallet.address);
    if (balance.gt(0)) {
      console.log(`Found dust on ${tokenAddr}:`, ethers.utils.formatUnits(balance, 18));
      const tx = await token.transfer(collector, balance);
      console.log(`  → Sending to collector, tx hash:`, tx.hash);
      await tx.wait();
      console.log(`  ✓ Swept ${tokenAddr}`);
    } else {
      console.log(`No dust on ${tokenAddr}`);
    }
  }
  console.log('Dust sweep complete.');
}

sweepDust().catch(err => {
  console.error('Error sweeping dust:', err);
});
```
––––––––––––––––––––––––––––––––––––––––––  

**How to run:**  
1. Create a new folder and `cd` into it.  
2. Save the above script as `dust‑sweeper.js`.  
3. Run `npm init -y && npm install ethers dotenv`.  
4. Create a file named `.env` and fill in your `RPC_URL`, `PRIVATE_KEY`, and `COLLECTOR_ADDRESS`.  
5. Edit the `TOKENS` array to include the ERC‑20 contracts you want to sweep.  
6. Run `node dust‑sweeper.js`.  

That will pick up any “dust” balances on those tokens and bundle them back to your main collector address. From here you can automate or extend it to pull a live token list from an on‑chain registry or block‑explorer API.
